      for (Instruction \*I : ChainOpsAndOperands) {
        if (CostCtx.SkipCostComputation.count(I))
          continue;
        InstructionCost C = CostCtx.getLegacyCost(I, VF);
        Cost \+= C;
        LLVM_DEBUG(dbgs() << "Cost of " << C << " for VF " << VF
                          << ": in-loop reduction op " << *I << "\\n");
        CostCtx.SkipCostComputation.insert(I);
      }
    }' \
       llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
